import React from 'react';
import {BLANK_TARGET} from "../constants";
import {connect} from "react-redux";

const bio = ({bio}) => (
    <React.Fragment>
        <img className="app-logo" src={bio.profile_image} alt={bio.full_name}/>
        <section className="bio">
            <div className="name">{bio.full_name}</div>
            <div className="role">
                <a href="https://en.wikipedia.org/wiki/Software_engineer" {...BLANK_TARGET}>Software Engineer</a>
            </div>
            <div>
                <ul className="social">{
                    bio.urls.map(
                        url => {
                            const className = `${url.className} social-fab`;
                            return <li key={url.link}><a className={className} href={url.link} {...BLANK_TARGET}><i
                                className={url.fab}/></a></li>
                        }
                    )
                }</ul>
            </div>
        </section>
    </React.Fragment>
);

const mapStateToProps = ({bio}) => {
    return {bio}
};

export default connect(mapStateToProps)(bio);