import React from 'react';
import {BLANK_TARGET} from "../constants";
import {connect} from "react-redux";

const experience = (props) => props.experience.map(exp =>
    <article key={exp.year_from} className="exp">
        <h2 className="article-heading">
            <span className="article-heading-main">
                <a className="btn btn-white fill-parent upper" href={exp.url} {...BLANK_TARGET}>{exp.org}</a>
            </span>
            <span className="article-heading-main">{exp.role.title}</span>
            <span className="article-heading-sub">{exp.year_from} - {exp.year_to}</span>
        </h2>
        <ul>{exp.role.duties.map(duty => <li key={duty}>{duty}</li>)}</ul>
    </article>
);

const mapStateToProps = ({experience}) => {
    return {experience};
};

export default connect(mapStateToProps)(experience);