import React from 'react';
import {BLANK_TARGET} from "../constants";
import {connect} from "react-redux";

const education = (props) => props.education.map(edu =>
    <article key={edu.course}>
        <h1 className="article-heading">
            <span className="article-heading-main">{edu.course}</span>
            <span className="article-heading-sub upper">{edu.from} - {edu.to}</span>
        </h1>
        <a className="btn btn-white fill-parent upper" href={edu.url} {...BLANK_TARGET}>{edu.institution}</a>
    </article>
);

const mapStateToProps = ({education}) => {
    return {education};
};

export default connect(mapStateToProps)(education);
